#!/usr/bin/env python3
# writer.py — Piece F1: port donna_find's matching engine into kriya_find.
# Adds word-level TOKENIZATION (split on non-alphanumeric, words 2+ chars, dedupe), a
# single combined OR across (token x text-column), and in-memory ranking by token hits.
# Fixes the bug where "Meher Aryan" could not match the stored "Meher & Aryan" (the &
# breaks a whole-phrase substring match), which starved her of ground truth. Display,
# tagging, fallback, and summary are preserved. kriya_tally/history untouched. Guarded.
import base64, os, sys

TARGET = os.path.join("src", "agent", "kriyaRead.js")
OLD_B64 = ""
NEW_B64 = ""
GUARD = "split(/[^"  # the tokenizer regex is the unambiguous marker of the new code

def main():
    if not os.path.exists(TARGET):
        print("[ERROR] %s not found. Run from the dream-os repo root." % TARGET); sys.exit(1)
    with open(TARGET, "r", encoding="utf-8") as f:
        content = f.read()
    if GUARD in content:
        print("[SKIP] kriya_find already tokenized — port already applied."); return
    old = base64.b64decode(OLD_B64).decode("utf-8")
    new = base64.b64decode(NEW_B64).decode("utf-8")
    n = content.count(old)
    if n != 1:
        print("[ERROR] executeFind anchor found %d time(s) (expected 1). File UNTOUCHED." % n); sys.exit(1)
    content = content.replace(old, new)
    with open(TARGET, "w", encoding="utf-8") as f:
        f.write(content)
    print("[OK] kriya_find now tokenizes like donna_find (split into words, OR each across fields, rank by hits).")
    print("     Gate: node --check src/agent/kriyaRead.js")

if __name__ == "__main__":
    main()
